import { EmployeeRepository } from '../repository/EmployeeRepository';
import { EmployeeValidator, ValidationResult } from '../validators/EmployeeValidator';

/**
 * Business logic service for Employee operations.
 * This layer contains testable business logic separated from CAP framework.
 */
export class EmployeeBusinessService {
  private repository: EmployeeRepository;

  constructor(repository: EmployeeRepository) {
    this.repository = repository;
  }

  /**
   * Generate the next sequential employee ID
   */
  async generateNextEmployeeID(): Promise<string> {
    const lastID = await this.repository.getLastEmployeeID();
    let nextNum = 10001;

    if (lastID) {
      const num = parseInt(lastID.replace(/^[iI]/, ''), 10);
      if (!isNaN(num)) nextNum = num + 1;
    }
    return `I${String(nextNum).padStart(5, '0')}`;
  }

  /**
   * Generate a unique email for an employee
   */
  async generateUniqueEmail(firstName: string, lastName: string): Promise<string | null> {
    const f = (firstName || '').trim().toLowerCase();
    const l = (lastName || '').trim().toLowerCase();
    if (!f || !l) return null;

    const base = `${f}.${l}`;
    const existingEmails = await this.repository.findEmailsByPattern(`${base}%@sap.com`);
    const taken = new Set(existingEmails);

    let email = `${base}@sap.com`;
    let counter = 1;

    while (taken.has(email)) {
      email = `${base}${counter}@sap.com`;
      counter++;
    }
    return email;
  }

  /**
   * Calculate remaining leaves
   */
  calculateRemainingLeaves(granted: number | null, used: number | null): number | null {
    const leavesGranted = granted ?? 0;
    const leavesUsed = used ?? 0;

    if (leavesUsed < 0 || leavesUsed > leavesGranted) {
      return null;
    }
    return leavesGranted - leavesUsed;
  }

  /**
   * Determine if deactivate action should be available
   */
  isDeactivatable(isActiveEntity: boolean | undefined, status: string): boolean {
    const isActive = isActiveEntity !== false;
    return isActive && status === 'Active';
  }

  /**
   * Determine if delete action should be available
   */
  isDeletable(isActiveEntity: boolean | undefined, status: string): boolean {
    const isActive = isActiveEntity !== false;
    return isActive && status === 'Obsolete';
  }

  /**
   * Validate employee data for save
   */
  validateEmployeeData(data: any): ValidationResult {
    // Required fields
    let result = EmployeeValidator.validateRequiredFields(data);
    if (!result.isValid) return result;

    // Name formats
    result = EmployeeValidator.validateName(data.firstName, 'First name');
    if (!result.isValid) return result;

    result = EmployeeValidator.validateName(data.lastName, 'Last name');
    if (!result.isValid) return result;

    // Phone
    result = EmployeeValidator.validatePhoneNumber(data.phoneNumber);
    if (!result.isValid) return result;

    // Role
    result = EmployeeValidator.validateRole(data.role);
    if (!result.isValid) return result;

    // Department
    result = EmployeeValidator.validateDepartment(data.department);
    if (!result.isValid) return result;

    // Bank details
    result = EmployeeValidator.validateBankDetails(data);
    if (!result.isValid) return result;

    result = EmployeeValidator.validateBankCode(data.bankCode);
    if (!result.isValid) return result;

    result = EmployeeValidator.validateBankName(data.bankName);
    if (!result.isValid) return result;

    result = EmployeeValidator.validateBankAccountNumber(data.bankAccountNumber);
    if (!result.isValid) return result;

    // Leaves
    result = EmployeeValidator.validateLeaves(data.annualLeavesGranted, data.annualLeavesUsed);
    if (!result.isValid) return result;

    // Ratings
    if (data.ratings?.length) {
      for (const rating of data.ratings) {
        result = EmployeeValidator.validateRating(rating);
        if (!result.isValid) return result;
      }
    }

    // Learnings
    if (data.assignedLearnings?.length) {
      for (const learning of data.assignedLearnings) {
        result = EmployeeValidator.validateLearning(learning);
        if (!result.isValid) return result;
      }
    }

    // Projects
    if (data.assignedProjects?.length) {
      for (const project of data.assignedProjects) {
        result = EmployeeValidator.validateProject(project);
        if (!result.isValid) return result;
      }
    }

    return { isValid: true };
  }

  /**
   * Check for duplicate bank account number
   */
  async checkDuplicateBankAccount(bankAccountNumber: string, excludeID: string): Promise<any> {
    return await this.repository.findByBankAccountNumber(bankAccountNumber, excludeID);
  }

  /**
   * Deactivate an employee (mark as obsolete)
   */
  async deactivateEmployee(ID: string): Promise<{ success: boolean; message: string; employee?: any }> {
    const employee = await this.repository.findById(ID);

    if (!employee) {
      return { success: false, message: 'Employee not found' };
    }
    if (employee.status === 'Obsolete') {
      return { success: false, message: `Employee ${employee.employeeID} is already obsolete` };
    }
    if (employee.status !== 'Active') {
      return { success: false, message: 'Only active employees can be marked obsolete' };
    }

    await this.repository.updateStatus(ID, 'Obsolete');
    return { 
      success: true, 
      message: `Employee ${employee.employeeID} (${employee.firstName} ${employee.lastName}) has been marked obsolete`,
      employee 
    };
  }

  /**
   * Permanently delete an employee
   */
  async permanentlyDeleteEmployee(ID: string): Promise<{ success: boolean; message: string; employee?: any }> {
    const employee = await this.repository.findById(ID);

    if (!employee) {
      return { success: false, message: 'Employee not found' };
    }
    if (employee.status !== 'Obsolete') {
      return { success: false, message: 'Only obsolete employees can be permanently deleted' };
    }

    await this.repository.deleteById(ID);
    return { 
      success: true, 
      message: `Employee ${employee.employeeID} (${employee.firstName} ${employee.lastName}) has been permanently deleted`,
      employee 
    };
  }
}

export default EmployeeBusinessService;

/**
 * Validation result interface
 */
export interface ValidationResult {
  isValid: boolean;
  message?: string;
}

/**
 * Employee data validation functions.
 * These are pure functions that can be easily unit tested.
 */
export class EmployeeValidator {
  private static readonly NAME_REGEX = /^[a-zA-Z\s'-]+$/;
  private static readonly PHONE_REGEX = /^\d{10}$/;
  private static readonly ROLE_REGEX = /^[a-zA-Z0-9\s\-\/]+$/;
  private static readonly DEPARTMENT_REGEX = /^[a-zA-Z\s&\-]+$/;
  private static readonly BANK_CODE_REGEX = /^[A-Z0-9]{8,11}$/i;
  private static readonly BANK_NAME_REGEX = /^[a-zA-Z\s&.]+$/;
  private static readonly BANK_ACCOUNT_REGEX = /^\d{8,20}$/;
  private static readonly REVIEWER_ID_REGEX = /^[a-zA-Z0-9]+$/;
  private static readonly YEAR_REGEX = /^\d{4}$/;

  /**
   * Validate required fields
   */
  static validateRequiredFields(data: any): ValidationResult {
    if (!data.firstName?.trim()) {
      return { isValid: false, message: 'First name is required' };
    }
    if (!data.lastName?.trim()) {
      return { isValid: false, message: 'Last name is required' };
    }
    if (!data.joiningDate) {
      return { isValid: false, message: 'Joining date is required' };
    }
    if (!data.phoneNumber?.trim()) {
      return { isValid: false, message: 'Phone number is required' };
    }
    if (!data.department?.trim()) {
      return { isValid: false, message: 'Department is required' };
    }
    if (!data.role?.trim()) {
      return { isValid: false, message: 'Role is required' };
    }
    return { isValid: true };
  }

  /**
   * Validate name format
   */
  static validateName(name: string, fieldName: string): ValidationResult {
    if (!this.NAME_REGEX.test(name)) {
      return { 
        isValid: false, 
        message: `${fieldName} must contain only letters, spaces, hyphens, or apostrophes` 
      };
    }
    return { isValid: true };
  }

  /**
   * Validate phone number format
   */
  static validatePhoneNumber(phone: string): ValidationResult {
    if (!this.PHONE_REGEX.test(phone)) {
      return { isValid: false, message: 'Phone number must be exactly 10 digits' };
    }
    return { isValid: true };
  }

  /**
   * Validate role format
   */
  static validateRole(role: string): ValidationResult {
    if (!this.ROLE_REGEX.test(role)) {
      return { 
        isValid: false, 
        message: 'Role must contain only letters, numbers, spaces, hyphens, or /' 
      };
    }
    return { isValid: true };
  }

  /**
   * Validate department format
   */
  static validateDepartment(department: string): ValidationResult {
    if (!this.DEPARTMENT_REGEX.test(department)) {
      return { 
        isValid: false, 
        message: 'Department must contain only letters, spaces, & or hyphens' 
      };
    }
    return { isValid: true };
  }

  /**
   * Validate bank details (all or none required)
   */
  static validateBankDetails(data: any): ValidationResult {
    const hasBankName = !!data.bankName?.trim();
    const hasBankCode = !!data.bankCode?.trim();
    const hasBankAccount = !!data.bankAccountNumber?.trim();

    if (hasBankName || hasBankCode || hasBankAccount) {
      if (!hasBankName) {
        return { isValid: false, message: 'Bank name is required when providing bank details' };
      }
      if (!hasBankCode) {
        return { isValid: false, message: 'Bank code is required when providing bank details' };
      }
      if (!hasBankAccount) {
        return { isValid: false, message: 'Bank account number is required when providing bank details' };
      }
    }
    return { isValid: true };
  }

  /**
   * Validate bank code format
   */
  static validateBankCode(bankCode: string): ValidationResult {
    if (bankCode && !this.BANK_CODE_REGEX.test(bankCode)) {
      return { isValid: false, message: 'Bank code must be 8-11 alphanumeric characters' };
    }
    return { isValid: true };
  }

  /**
   * Validate bank name format
   */
  static validateBankName(bankName: string): ValidationResult {
    if (bankName && !this.BANK_NAME_REGEX.test(bankName)) {
      return { isValid: false, message: 'Bank name must contain only letters, spaces, & or .' };
    }
    return { isValid: true };
  }

  /**
   * Validate bank account number format
   */
  static validateBankAccountNumber(accountNumber: string): ValidationResult {
    if (accountNumber && !this.BANK_ACCOUNT_REGEX.test(accountNumber)) {
      return { isValid: false, message: 'Bank account number must be 8-20 digits' };
    }
    return { isValid: true };
  }

  /**
   * Validate leaves
   */
  static validateLeaves(granted: number | undefined, used: number | undefined): ValidationResult {
    if (used !== undefined && granted !== undefined) {
      if (used > granted) {
        return { 
          isValid: false, 
          message: `Leaves used (${used}) cannot exceed leaves granted (${granted})` 
        };
      }
      if (used < 0) {
        return { isValid: false, message: 'Leaves used cannot be negative' };
      }
    }
    return { isValid: true };
  }

  /**
   * Validate rating entry
   */
  static validateRating(rating: any): ValidationResult {
    if (!rating.year?.trim()) {
      return { isValid: false, message: 'Rating year is required' };
    }
    if (rating.rating === undefined || rating.rating === null) {
      return { isValid: false, message: 'Rating value is required' };
    }
    if (!rating.reviewerID?.trim()) {
      return { isValid: false, message: 'Reviewer ID is required' };
    }
    if (!this.REVIEWER_ID_REGEX.test(rating.reviewerID)) {
      return { isValid: false, message: 'Reviewer ID must contain only letters and numbers' };
    }
    if (rating.rating < 1 || rating.rating > 5) {
      return { isValid: false, message: `Rating must be between 1 and 5. Got: ${rating.rating}` };
    }
    const currentYear = new Date().getFullYear();
    if (!this.YEAR_REGEX.test(rating.year) || parseInt(rating.year) < 2000 || parseInt(rating.year) > currentYear) {
      return { isValid: false, message: `Year must be between 2000 and ${currentYear}. Got: ${rating.year}` };
    }
    return { isValid: true };
  }

  /**
   * Validate learning entry
   */
  static validateLearning(learning: any): ValidationResult {
    if (!learning.learningMaster_ID) {
      return { isValid: false, message: 'Learning is required' };
    }
    if (!learning.assignedDate) {
      return { isValid: false, message: 'Learning assigned date is required' };
    }
    if (learning.completedDate && learning.completedDate < learning.assignedDate) {
      return { isValid: false, message: 'Learning completed date cannot be before assigned date' };
    }
    return { isValid: true };
  }

  /**
   * Validate project entry
   */
  static validateProject(project: any): ValidationResult {
    if (!project.projectMaster_ID) {
      return { isValid: false, message: 'Project is required' };
    }
    if (!project.assignedDate) {
      return { isValid: false, message: 'Project assigned date is required' };
    }
    if (project.completedDate && project.completedDate < project.assignedDate) {
      return { isValid: false, message: 'Project completed date cannot be before assigned date' };
    }
    return { isValid: true };
  }
}

export default EmployeeValidator;

import cds from '@sap/cds';

/**
 * Repository layer for Employee-related database operations.
 * This abstraction allows unit tests to mock database operations
 * without directly mocking CAP framework functions.
 */
export class EmployeeRepository {
  private db: any;
  private dbEmployees: any;

  constructor(db?: any) {
    this.db = db;
  }

  async initialize(): Promise<void> {
    if (!this.db) {
      this.db = await cds.connect.to('db');
    }
    this.dbEmployees = cds.entities('db').Employees;
  }

  /**
   * Get the last employee ID ordered descending
   */
  async getLastEmployeeID(): Promise<string | null> {
    const last = await this.db.run(
      SELECT.one.from(this.dbEmployees).columns('employeeID').orderBy('employeeID desc')
    );
    return last?.employeeID || null;
  }

  /**
   * Find emails matching a pattern
   */
  async findEmailsByPattern(pattern: string): Promise<string[]> {
    const matches = await this.db.run(
      SELECT.from(this.dbEmployees)
        .columns('email')
        .where({ email: { like: pattern } })
    );
    return matches.map((e: any) => e.email);
  }

  /**
   * Find employee by ID
   */
  async findById(ID: string): Promise<any> {
    return await this.db.run(
      SELECT.one.from(this.dbEmployees).where({ ID })
    );
  }

  /**
   * Find employee by bank account number (excluding a specific ID)
   */
  async findByBankAccountNumber(bankAccountNumber: string, excludeID: string): Promise<any> {
    return await this.db.run(
      SELECT.one.from(this.dbEmployees)
        .columns('employeeID', 'firstName', 'lastName')
        .where({ bankAccountNumber, ID: { '!=': excludeID } })
    );
  }

  /**
   * Update employee status
   */
  async updateStatus(ID: string, status: string): Promise<void> {
    await this.db.run(
      UPDATE(this.dbEmployees).set({ status }).where({ ID })
    );
  }

  /**
   * Delete employee by ID
   */
  async deleteById(ID: string): Promise<void> {
    await this.db.run(
      DELETE.from(this.dbEmployees).where({ ID })
    );
  }

  /**
   * Get beginner courses (initialLevel = true)
   */
  async getBeginnerCourses(LearningsMasterData: any): Promise<any[]> {
    return await this.db.run(
      SELECT.from(LearningsMasterData).where({ initialLevel: true })
    );
  }

  /**
   * Insert learning draft
   */
  async insertLearningDraft(entry: any): Promise<void> {
    await this.db.run(
      INSERT.into('EmployeeService.Learnings.drafts').entries(entry)
    );
  }
}

export default EmployeeRepository;
